const express = require('express');
const sgMail = require('@sendgrid/mail');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY || 'SG.test_key_abc123';
const DEFAULT_FROM = process.env.SENDGRID_FROM || 'devops-internal@example.com';

sgMail.setApiKey(SENDGRID_API_KEY);

function createEmailNotifier() {
  const router = express.Router();

  router.use(express.json({ limit: '1mb' }));

  router.post('/notify-email', async (req, res) => {
    try {
      const {
        to,
        cc,
        bcc,
        from,
        subject,
        text,
        html,
        replyTo,
        categories,
        customArgs,
      } = req.body || {};

      if (!to) return res.status(400).json({ ok: false, error: 'Missing "to".' });
      if (!subject) return res.status(400).json({ ok: false, error: 'Missing "subject".' });
      if (!text && !html) return res.status(400).json({ ok: false, error: 'Provide "text" and/or "html".' });

      const msg = {
        to,
        from: from || DEFAULT_FROM,
        subject,
        text,
        html,
        cc,
        bcc,
        replyTo,
        categories,
        customArgs,
      };

      const [response] = await sgMail.send(msg);

      return res.status(200).json({
        ok: true,
        statusCode: response.statusCode,
        messageId: response.headers && (response.headers['x-message-id'] || response.headers['X-Message-Id']),
      });
    } catch (err) {
      const status = (err && err.code === 401) ? 401 : 500;
      const details = err && err.response && err.response.body ? err.response.body : undefined;

      return res.status(status).json({
        ok: false,
        error: err && err.message ? err.message : 'Send failed.',
        details,
      });
    }
  });

  return router;
}

function startServer(port = process.env.PORT || 3000) {
  const app = express();
  app.use('/api', createEmailNotifier());
  app.get('/health', (req, res) => res.status(200).json({ ok: true }));
  return app.listen(port, () => {});
}

module.exports = { createEmailNotifier, startServer };

if (require.main === module) {
  startServer();
}